#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    vec3 reta = texture( sampler_pc_main, vec2(vUv.x-0.005, vUv.y) ).xyz;
    vec3 retb = texture(sampler_fc_main, vec2(vUv.x-0.005, vUv.y)).xyz;
    vec3 retc = texture(sampler_fc_rand00, vec2(vUv.x-0.005, vUv.y)).xyz;
    vec3 retd = texture(sampler_fc_rand00, vec2(vUv.x-0.005, vUv.y)).xyz;
    ret = mix(retb, reta, clamp01(vUv.x+0.5));
    ret = mix(retd, retc, ret);
   // darken (decay) over uTime
    ret *= 1.00; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float cutoff = 0.95;
int n = 1;
float s = 0.3;
int depth = 3; //number of fractal iterations

for(int i = 0; i<depth;i++){
   c = (vUv-0.5)*2*uAspect.wz;
   numerator = (c + vec2(q21,q22))*64;
   denominator = c + vec2(q23,q24);
   fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,
                      numerator.y*denominator.x - numerator.x*denominator.y)/
                      (denominator.x*denominator.x + denominator.y*denominator.y);
   c = fraction-0.5;
   ang_hq = n*atan(c.x,c.y);
   spiral = vec2(ang_hq*q25+q26,s*uAspect.w*log(length(c))+q27);
   vUv = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*cutoff; // mirror
}
vec2 uv1 = vec2(vUv.x-q6, vUv.y-q5);

vec2 hor = vec2 (uTexSize.z*1,0);
vec2 ver = vec2 (0,uTexSize.w*1);
float dx = GetPixel (vUv-hor) - GetPixel (vUv+hor);
float dy = GetPixel (vUv-ver) - GetPixel (vUv+ver);
vec2 dz = vec2 (dx,dy);

uv1 = uv1*0+.3*cos(uv1*2) - dz;
float dots = clamp01(.04/length(uv1));
uv1 = uv1*0+.3*cos(uv1*12) - 9*dz;
vec3 dots2 = clamp01(.04/length(uv1));
dots -= lum(GetBlur2(vUv));

ret = dots + GetPixel(vUv)*12*dots2;


  fragColor = ret;
}
